            var conditions = new List<string>();
            var parameters = new List<SqlParameter>();
            int paramIndex = 0;

            var allowedCols = AllowedColumns[tableName];

            // Filter format: filter_ColumnName_Operator=Value
            // Example: filter_Region_eq=West&filter_Amount_gt=1000
            foreach (var key in query.Keys)
            {
                if (!key.StartsWith("filter_", StringComparison.OrdinalIgnoreCase))
                    continue;

                var parts = key.Split('_');
                if (parts.Length != 3)
                {
                    return (null, null, $"Invalid filter format: '{key}'. Expected format: filter_ColumnName_Operator");
                }

                string columnName = parts[1];
                string operatorName = parts[2];
                string value = query[key];

                // Validate column name against whitelist
                if (!allowedCols.Contains(columnName))
                {
                    return (null, null, $"Invalid column name: '{columnName}'. Allowed columns for {tableName}: {string.Join(", ", allowedCols)}");
                }

                // Get canonical column name
                string safeColumnName = GetCanonicalColumnName(columnName, allowedCols);

                // Validate operator against whitelist
                if (!AllowedOperators.Contains(operatorName))
                {
                    return (null, null, $"Invalid operator: '{operatorName}'. Allowed operators: {string.Join(", ", AllowedOperators)}");
                }

                if (string.Equals(operatorName, "in", StringComparison.OrdinalIgnoreCase))
                {
                    // Handle IN operator with multiple values
                    var inValues = value.Split(',');
                    var inParams = new List<string>();
                    foreach (var inVal in inValues)
