                        string paramName = $"@p{paramIndex++}";
                        inParams.Add(paramName);
                        parameters.Add(new SqlParameter(paramName, inVal.Trim()));
                    }
                    conditions.Add($"[{safeColumnName}] IN ({string.Join(", ", inParams)})");
                }
                else
                {
                    string sqlOperator = MapOperator(operatorName);
                    string paramName = $"@p{paramIndex++}";

                    if (string.Equals(operatorName, "like", StringComparison.OrdinalIgnoreCase))
                    {
                        // For LIKE, wrap value with wildcards
                        conditions.Add($"[{safeColumnName}] {sqlOperator} {paramName}");
                        parameters.Add(new SqlParameter(paramName, $"%{EscapeLikePattern(value)}%"));
                    }
                    else
                    {
                        conditions.Add($"[{safeColumnName}] {sqlOperator} {paramName}");
                        parameters.Add(new SqlParameter(paramName, value));
                    }
                }
            }

            return (conditions, parameters, null);
        }

        private static string GetCanonicalColumnName(string columnName, HashSet<string> allowedCols)
        {
            foreach (var col in allowedCols)
