        private static string EscapeLikePattern(string pattern)
        {
            return pattern
                .Replace("[", "[[]")
                .Replace("%", "[%]")
                .Replace("_", "[_]");
        }

        private static string MapOperator(string op)
        {
            return op.ToLowerInvariant() switch
            {
                "eq" => "=",
                "neq" => "!=",
                "gt" => ">",
                "gte" => ">=",
                "lt" => "<",
                "lte" => "<=",
                "like" => "LIKE",
                _ => throw new ArgumentException($"Unsupported operator: {op}")
            };
        }

        private static (string Columns, string Error) ParseSelectColumns(string selectParam, string tableName)
        {
            if (string.IsNullOrWhiteSpace(selectParam))
            {
                return ("*", null);
            }

            var allowedCols = AllowedColumns[tableName];
            var requestedColumns = selectParam.Split(',');
            var validatedColumns = new List<string>();

            foreach (var col in requestedColumns)
            {
                string trimmedCol = col.Trim();
                if (!allowedCols.Contains(trimmedCol))
                {
                    return (null, $"Invalid select column: '{trimmedCol}'. Allowed columns for {tableName}: {string.Join(", ", allowedCols)}");
