                string canonicalCol = GetCanonicalColumnName(trimmedCol, allowedCols);
                validatedColumns.Add($"[{canonicalCol}]");
            }

            return (string.Join(", ", validatedColumns), null);
        }

        private static (string SortClause, string Error) ParseSort(string sortColumn, string sortDirection, string tableName)
