            // All user values are parameterized
            string sql = $"SELECT {selectColumns} FROM [{tableName}]";

            if (conditions != null && conditions.Count > 0)
            {
                sql += " WHERE " + string.Join(" AND ", conditions);
            }

            if (!string.IsNullOrEmpty(sortClause))
            {
                sql += $" {sortClause}";
            }
            else
            {
                // OFFSET/FETCH requires ORDER BY
                sql += " ORDER BY (SELECT NULL)";
            }

            sql += " OFFSET @offset ROWS FETCH NEXT @top ROWS ONLY";

            parameters.Add(new SqlParameter("@offset", offset));
            parameters.Add(new SqlParameter("@top", top));

            return (sql, parameters);
        }

        private static async Task<List<Dictionary<string, object>>> ExecuteQueryAsync(
            string connectionString, string sql, List<SqlParameter> parameters, ILogger log)
